unit lipdecide;

{$mode objfpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

const
  LIC_COUNT = 15;

function RoundToSixSignificantDigits(Value: real): real;
var
  Scaled: real;
  Exponent10: integer;
  Factor: real;
begin
  if Value = 0.0 then
    Exit(0.0);

  Scaled := Abs(Value);
  Exponent10 := 0;

  if Scaled >= 1.0 then
  begin
    while Scaled >= 10.0 do
    begin
      Scaled := Scaled / 10.0;
      Inc(Exponent10);
    end;
  end
  else
  begin
    while Scaled < 1.0 do
    begin
      Scaled := Scaled * 10.0;
      Dec(Exponent10);
    end;
  end;

  Factor := IntPower(10.0, 5 - Exponent10);
  Result := Round(Value * Factor) / Factor;
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  RoundedA: real;
  RoundedB: real;
begin
  RoundedA := RoundToSixSignificantDigits(A);
  RoundedB := RoundToSixSignificantDigits(B);

  if RoundedA < RoundedB then
    Result := LT
  else if RoundedA > RoundedB then
    Result := GT
  else
    Result := EQ;
end;

function DistanceBetweenPoints(I, J: integer): real;
var
  DX: real;
  DY: real;
begin
  DX := X[J] - X[I];
  DY := Y[J] - Y[I];
  Result := Sqrt(DX * DX + DY * DY);
end;

function PointsCoincide(I, J: integer): boolean;
begin
  Result := (REALCOMPARE(X[I], X[J]) = EQ) and (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function TriangleArea(I, J, K: integer): real;
begin
  Result := Abs(
    X[I] * (Y[J] - Y[K]) +
    X[J] * (Y[K] - Y[I]) +
    X[K] * (Y[I] - Y[J])
  ) / 2.0;
end;

function MaxReal(A, B: real): real;
begin
  if REALCOMPARE(A, B) = LT then
    Result := B
  else
    Result := A;
end;

function MaxOfThree(A, B, C: real): real;
begin
  Result := MaxReal(MaxReal(A, B), C);
end;

function AngleConditionMet(I, J, K: integer): boolean;
var
  V1X: real;
  V1Y: real;
  V2X: real;
  V2Y: real;
  Len1: real;
  Len2: real;
  CosineValue: real;
  AngleValue: real;
begin
  if PointsCoincide(I, J) or PointsCoincide(K, J) then
    Exit(False);

  V1X := X[I] - X[J];
  V1Y := Y[I] - Y[J];
  V2X := X[K] - X[J];
  V2Y := Y[K] - Y[J];

  Len1 := Sqrt(V1X * V1X + V1Y * V1Y);
  Len2 := Sqrt(V2X * V2X + V2Y * V2Y);
  CosineValue := (V1X * V2X + V1Y * V2Y) / (Len1 * Len2);

  if REALCOMPARE(CosineValue, 1.0) = GT then
    CosineValue := 1.0
  else if REALCOMPARE(CosineValue, -1.0) = LT then
    CosineValue := -1.0;

  AngleValue := ArcCos(CosineValue);
  Result :=
    (REALCOMPARE(AngleValue, PI - PARAMETERS.EPSILON) = LT) or
    (REALCOMPARE(AngleValue, PI + PARAMETERS.EPSILON) = GT);
end;

function CanBeContainedInCircle(I, J, K: integer; Radius: real): boolean;
var
  A: real;
  B: real;
  C: real;
  MaxSide: real;
  SumOtherSquares: real;
  MaxSquare: real;
  AreaValue: real;
  MinimumRadius: real;
begin
  A := DistanceBetweenPoints(J, K);
  B := DistanceBetweenPoints(I, K);
  C := DistanceBetweenPoints(I, J);
  MaxSide := MaxOfThree(A, B, C);

  if REALCOMPARE(MaxSide, 0.0) = EQ then
    Exit(True);

  if REALCOMPARE(MaxSide, A) = EQ then
    SumOtherSquares := B * B + C * C
  else if REALCOMPARE(MaxSide, B) = EQ then
    SumOtherSquares := A * A + C * C
  else
    SumOtherSquares := A * A + B * B;

  MaxSquare := MaxSide * MaxSide;
  AreaValue := TriangleArea(I, J, K);

  if (REALCOMPARE(AreaValue, 0.0) = EQ) or (REALCOMPARE(MaxSquare, SumOtherSquares) <> LT) then
    MinimumRadius := MaxSide / 2.0
  else
    MinimumRadius := (A * B * C) / (4.0 * AreaValue);

  Result := REALCOMPARE(MinimumRadius, Radius) <> GT;
end;

function QuadrantOfPoint(Index: integer): integer;
var
  XCompare: COMPTYPE;
  YCompare: COMPTYPE;
begin
  XCompare := REALCOMPARE(X[Index], 0.0);
  YCompare := REALCOMPARE(Y[Index], 0.0);

  if (XCompare <> LT) and (YCompare <> LT) then
    Result := 1
  else if (XCompare = LT) and (YCompare <> LT) then
    Result := 2
  else if (XCompare <> GT) and (YCompare = LT) then
    Result := 3
  else
    Result := 4;
end;

function LIC1Met: boolean;
var
  I: integer;
begin
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(DistanceBetweenPoints(I, I + 1), PARAMETERS.LENGTH1) = GT then
      Exit(True);
  Result := False;
end;

function LIC2Met: boolean;
var
  I: integer;
begin
  for I := 1 to NUMPOINTS - 2 do
    if not CanBeContainedInCircle(I, I + 1, I + 2, PARAMETERS.RADIUS1) then
      Exit(True);
  Result := False;
end;

function LIC3Met: boolean;
var
  I: integer;
begin
  for I := 1 to NUMPOINTS - 2 do
    if AngleConditionMet(I, I + 1, I + 2) then
      Exit(True);
  Result := False;
end;

function LIC4Met: boolean;
var
  I: integer;
begin
  for I := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(I, I + 1, I + 2), PARAMETERS.AREA1) = GT then
      Exit(True);
  Result := False;
end;

function LIC5Met: boolean;
var
  StartIndex: integer;
  Offset: integer;
  QuadrantCount: integer;
  Seen: array[1..4] of boolean;
  Quadrant: integer;
begin
  for StartIndex := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    Seen[1] := False;
    Seen[2] := False;
    Seen[3] := False;
    Seen[4] := False;
    QuadrantCount := 0;

    for Offset := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      Quadrant := QuadrantOfPoint(StartIndex + Offset);
      if not Seen[Quadrant] then
      begin
        Seen[Quadrant] := True;
        Inc(QuadrantCount);
      end;
    end;

    if QuadrantCount > PARAMETERS.QUADS then
      Exit(True);
  end;

  Result := False;
end;

function LIC6Met: boolean;
var
  I: integer;
begin
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[I + 1], X[I]) = LT then
      Exit(True);
  Result := False;
end;

function WindowHasPointFartherThan(StartIndex, EndIndex: integer; Dist: real): boolean;
var
  I: integer;
  DX: real;
  DY: real;
  Denominator: real;
  PointDistance: real;
begin
  if PointsCoincide(StartIndex, EndIndex) then
  begin
    for I := StartIndex + 1 to EndIndex - 1 do
      if REALCOMPARE(DistanceBetweenPoints(StartIndex, I), Dist) = GT then
        Exit(True);
  end
  else
  begin
    DX := X[EndIndex] - X[StartIndex];
    DY := Y[EndIndex] - Y[StartIndex];
    Denominator := Sqrt(DX * DX + DY * DY);

    for I := StartIndex + 1 to EndIndex - 1 do
    begin
      PointDistance := Abs((X[I] - X[StartIndex]) * DY - (Y[I] - Y[StartIndex]) * DX) / Denominator;
      if REALCOMPARE(PointDistance, Dist) = GT then
        Exit(True);
    end;
  end;

  Result := False;
end;

function LIC7Met: boolean;
var
  StartIndex: integer;
  EndIndex: integer;
begin
  if NUMPOINTS < 3 then
    Exit(False);

  for StartIndex := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    EndIndex := StartIndex + PARAMETERS.N_PTS - 1;
    if WindowHasPointFartherThan(StartIndex, EndIndex, PARAMETERS.DIST) then
      Exit(True);
  end;

  Result := False;
end;

function LIC8Met: boolean;
var
  I: integer;
  J: integer;
begin
  if NUMPOINTS < 3 then
    Exit(False);

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(DistanceBetweenPoints(I, J), PARAMETERS.LENGTH1) = GT then
      Exit(True);
  end;

  Result := False;
end;

function LIC9Met: boolean;
var
  I: integer;
  J: integer;
  K: integer;
begin
  if NUMPOINTS < 5 then
    Exit(False);

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if not CanBeContainedInCircle(I, J, K, PARAMETERS.RADIUS1) then
      Exit(True);
  end;

  Result := False;
end;

function LIC10Met: boolean;
var
  I: integer;
  J: integer;
  K: integer;
begin
  if NUMPOINTS < 5 then
    Exit(False);

  for I := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    J := I + PARAMETERS.C_PTS + 1;
    K := J + PARAMETERS.D_PTS + 1;
    if AngleConditionMet(I, J, K) then
      Exit(True);
  end;

  Result := False;
end;

function LIC11Met: boolean;
var
  I: integer;
  J: integer;
  K: integer;
begin
  if NUMPOINTS < 5 then
    Exit(False);

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    if REALCOMPARE(TriangleArea(I, J, K), PARAMETERS.AREA1) = GT then
      Exit(True);
  end;

  Result := False;
end;

function LIC12Met: boolean;
var
  I: integer;
  J: integer;
begin
  if NUMPOINTS < 3 then
    Exit(False);

  for I := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    J := I + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[J], X[I]) = LT then
      Exit(True);
  end;

  Result := False;
end;

function LIC13Met: boolean;
var
  I: integer;
  J: integer;
  FoundGreater: boolean;
  FoundLess: boolean;
  DistanceValue: real;
begin
  if NUMPOINTS < 3 then
    Exit(False);

  FoundGreater := False;
  FoundLess := False;

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    DistanceValue := DistanceBetweenPoints(I, J);

    if REALCOMPARE(DistanceValue, PARAMETERS.LENGTH1) = GT then
      FoundGreater := True;
    if REALCOMPARE(DistanceValue, PARAMETERS.LENGTH2) = LT then
      FoundLess := True;

    if FoundGreater and FoundLess then
      Exit(True);
  end;

  Result := False;
end;

function LIC14Met: boolean;
var
  I: integer;
  J: integer;
  K: integer;
  FoundOutside: boolean;
  FoundInside: boolean;
begin
  if NUMPOINTS < 5 then
    Exit(False);

  FoundOutside := False;
  FoundInside := False;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;

    if not CanBeContainedInCircle(I, J, K, PARAMETERS.RADIUS1) then
      FoundOutside := True;
    if CanBeContainedInCircle(I, J, K, PARAMETERS.RADIUS2) then
      FoundInside := True;

    if FoundOutside and FoundInside then
      Exit(True);
  end;

  Result := False;
end;

function LIC15Met: boolean;
var
  I: integer;
  J: integer;
  K: integer;
  AreaValue: real;
  FoundGreater: boolean;
  FoundLess: boolean;
begin
  if NUMPOINTS < 5 then
    Exit(False);

  FoundGreater := False;
  FoundLess := False;

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    AreaValue := TriangleArea(I, J, K);

    if REALCOMPARE(AreaValue, PARAMETERS.AREA1) = GT then
      FoundGreater := True;
    if REALCOMPARE(AreaValue, PARAMETERS.AREA2) = LT then
      FoundLess := True;

    if FoundGreater and FoundLess then
      Exit(True);
  end;

  Result := False;
end;

procedure DECIDE;
var
  I: integer;
  J: integer;
  RowAllTrue: boolean;
begin
  CMV[1] := LIC1Met;
  CMV[2] := LIC2Met;
  CMV[3] := LIC3Met;
  CMV[4] := LIC4Met;
  CMV[5] := LIC5Met;
  CMV[6] := LIC6Met;
  CMV[7] := LIC7Met;
  CMV[8] := LIC8Met;
  CMV[9] := LIC9Met;
  CMV[10] := LIC10Met;
  CMV[11] := LIC11Met;
  CMV[12] := LIC12Met;
  CMV[13] := LIC13Met;
  CMV[14] := LIC14Met;
  CMV[15] := LIC15Met;

  for I := 1 to LIC_COUNT do
    for J := 1 to LIC_COUNT do
      if I <> J then
        case LCM[I, J] of
          NOTUSED: PUM[I, J] := True;
          ORR: PUM[I, J] := CMV[I] or CMV[J];
          ANDD: PUM[I, J] := CMV[I] and CMV[J];
        end;

  for I := 1 to LIC_COUNT do
  begin
    if not PUM[I, I] then
      FUV[I] := True
    else
    begin
      RowAllTrue := True;
      for J := 1 to LIC_COUNT do
        if not PUM[I, J] then
        begin
          RowAllTrue := False;
          Break;
        end;
      FUV[I] := RowAllTrue;
    end;
  end;

  LAUNCH := True;
  for I := 1 to LIC_COUNT do
    if not FUV[I] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

end.
